{"content":"package com.ichi2.anki

import android.content.Intent
import android.net.Uri
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.IntentHandler.Companion.getLaunchType
import com.ichi2.anki.IntentHandler.LaunchType
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
class IntentHandlerCsvTest {

    @Test
    fun csvMimeTypesReturnTextImport() {
        val mimeTypes = listOf(
            "text/csv",
            "application/csv",
            "application/x-csv",
            "application/vnd.ms-excel",
            "application/vnd.msexcel"
        )

        for (mimeType in mimeTypes) {
            val intent = Intent(Intent.ACTION_VIEW)
            intent.setDataAndType(Uri.parse("content://valid"), mimeType)
            val expected = getLaunchType(intent)

            assertThat("MimeType: $mimeType should be TEXT_IMPORT", expected, equalTo(LaunchType.TEXT_IMPORT))
        }
    }
}
